        processor.addProduct("Apple", 1.50);
        processor.addProduct("Banana", 0.75);

        String orderString = "Apple–1";
        int orderPrice = processor.calculateOrderPrice(orderString);
        System.out.println("Order Price: $" + orderPrice);
    }
}
```

